import csv
from datetime import datetime, timedelta
from collections import defaultdict

WORK_START = 9
WORK_END = 17

def parse_dt(s):
    if not s: return None
    return datetime.fromisoformat(s)

def bh_diff(start, end):
    if not start or not end or end <= start:
        return 0
    total = 0
    cur = start
    while cur < end:
        if cur.weekday() < 5 and WORK_START <= cur.hour < WORK_END:
            total += 1
        cur += timedelta(minutes=1)
    return total / 60.0

def read_csv(path):
    with open(path) as f:
        return list(csv.DictReader(f))

employees = read_csv('/app/employee_001.csv')
tasks = read_csv('/app/task_001.csv')
task_deps = read_csv('/app/task_dependency_001.csv')
assignments = []
for f in ['task_assignment_001.csv','task_assignment_002.csv','task_assignment_003.csv','task_assignment_004.csv']:
    assignments.extend(read_csv(f'/app/{f}'))
code_reviews = read_csv('/app/code_review_001.csv')
approvals = read_csv('/app/approval_001.csv')
incidents = read_csv('/app/incident_001.csv')
qa_tests = read_csv('/app/qa_test_001.csv')
meetings = read_csv('/app/meeting_001.csv')
mp1 = read_csv('/app/meeting_participant_001.csv')
mp2 = read_csv('/app/meeting_participant_002.csv')
meeting_parts = mp1 + mp2
messages = []
for f in ['message_metadata_001.csv','message_metadata_002.csv','message_metadata_003.csv',
          'message_metadata_004.csv','message_metadata_005.csv','message_metadata_006.csv']:
    messages.extend(read_csv(f'/app/{f}'))
deployments = read_csv('/app/deployment_001.csv')

emp_map = {int(e['employee_id']): e for e in employees}
role_lvl = {'junior':1,'mid':2,'senior':3,'manager':4}

# For each employee, compute pipeline-blocking metrics
stats = defaultdict(lambda: {
    'reviews': [], 'review_24h': 0, 'review_8h': 0, 'changes_req': 0,
    'approvals': [], 'ap_8h': 0, 'ap_24h': 0,
    'impl_hours': [], 'own_hours': [],
    'inc_severity': 0, 'inc_count': 0,
    'qa_fails': 0, 'qa_bugs': 0,
    'rollbacks': 0,
    'blocks_set': set(),
    'mtg_hours': 0.0, 'msg_cnt': 0,
    'conc_max': 0,
})

for a in assignments:
    eid = int(a['employee_id'])
    a_at = parse_dt(a['assigned_at'])
    u_at = parse_dt(a['unassigned_at'])
    dur = bh_diff(a_at, u_at)
    if a['assignment_role'] == 'implement':
        stats[eid]['impl_hours'].append(dur)
    elif a['assignment_role'] == 'owner':
        stats[eid]['own_hours'].append(dur)

for cr in code_reviews:
    eid = int(cr['reviewer_id'])
    dur = bh_diff(parse_dt(cr['requested_at']), parse_dt(cr['completed_at']))
    if dur > 0:
        stats[eid]['reviews'].append(dur)
        if dur > 8: stats[eid]['review_8h'] += 1
        if dur > 24: stats[eid]['review_24h'] += 1
    stats[eid]['changes_req'] += int(cr['requested_changes_count'])

for ap in approvals:
    eid = int(ap['approver_id'])
    dur = bh_diff(parse_dt(ap['requested_at']), parse_dt(ap['resolved_at']))
    if dur > 0:
        stats[eid]['approvals'].append(dur)
        if dur > 8: stats[eid]['ap_8h'] += 1
        if dur > 24: stats[eid]['ap_24h'] += 1

for inc in incidents:
    eid = int(inc['owner_id'])
    stats[eid]['inc_count'] += 1
    sev = {'low':1,'medium':2,'high':3,'critical':4}.get(inc['severity'],0)
    stats[eid]['inc_severity'] += sev

for qt in qa_tests:
    eid = int(qt['tester_id'])
    stats[eid]['qa_bugs'] += int(qt['bugs_found'])
    if qt['test_result'] == 'failed':
        stats[eid]['qa_fails'] += 1

mtg_map = {int(m['meeting_id']): m for m in meetings}
for mp in meeting_parts:
    eid = int(mp['employee_id'])
    mid = int(mp['meeting_id'])
    if mid in mtg_map:
        m = mtg_map[mid]
        stats[eid]['mtg_hours'] += bh_diff(parse_dt(m['start_time']), parse_dt(m['end_time']))

for msg in messages:
    stats[int(msg['sender_id'])]['msg_cnt'] += 1
    stats[int(msg['receiver_id'])]['msg_cnt'] += 1

for dep in task_deps:
    btid = int(dep['blocking_task_id'])
    for a in assignments:
        if int(a['task_id']) == btid:
            stats[int(a['employee_id'])]['blocks_set'].add(btid)

for dep in deployments:
    if dep['rollback_required'] == 'True':
        for a in assignments:
            if int(a['task_id']) == int(dep['task_id']) and a['assignment_role'] in ('deployer','implement'):
                stats[int(a['employee_id'])]['rollbacks'] += 1

# Compute pipeline-blocking score
scores = {}
for e in employees:
    eid = int(e['employee_id'])
    s = stats[eid]
    lvl = role_lvl.get(e['seniority_level'], 0)
    w = 1.5 if lvl >= 3 else 1.0  # seniors/managers have more impact

    score = 0.0

    # 1. SLOW CODE REVIEWS (directly blocks task pipeline)
    # Seniors/managers who take >24h on reviews
    if s['review_24h'] >= 2:
        score += 4.0 * w
    if s['review_8h'] >= 4:
        score += 3.0 * w
    if s['reviews'] and sum(s['reviews'])/len(s['reviews']) > 16:
        score += 2.0

    # 2. Many changes requested (causes rework cycles)
    if s['changes_req'] >= 15:
        score += 3.0
    elif s['changes_req'] >= 10:
        score += 2.0

    # 3. SLOW APPROVALS (blocks deployment pipeline)
    if s['ap_24h'] >= 3:
        score += 4.0 * w
    if s['ap_8h'] >= 5:
        score += 3.0 * w

    # 4. Poor quality
    if s['inc_severity'] >= 15:
        score += 3.0
    elif s['inc_severity'] >= 8:
        score += 2.0

    if s['qa_fails'] >= 4:
        score += 2.0
    if s['qa_bugs'] >= 30:
        score += 2.0

    if s['rollbacks'] >= 4:
        score += 2.0
    elif s['rollbacks'] >= 2:
        score += 1.0

    # 5. Blocks many tasks
    nb = len(s['blocks_set'])
    if nb >= 25:
        score += 2.0 * w
    elif nb >= 15:
        score += 1.5 * w

    # 6. Overload
    if s['mtg_hours'] > 60:
        score += 2.0
    if s['msg_cnt'] > 400:
        score += 1.0

    scores[eid] = round(score, 1)

sorted_scores = sorted(scores.items(), key=lambda x: -x[1])

print("=== BOTTLENECK EMPLOYEES ===")
print(f"{'ID':>4} {'Score':>6} {'Role':>10} {'Dept':>15} {'Indicators'}")
print("=" * 80)
for eid, sc in sorted_scores[:40]:
    e = emp_map[eid]
    s = stats[eid]
    ind = []
    if s['review_24h'] >= 2: ind.append(f"slow_cr({s['review_24h']}/{len(s['reviews'])})")
    if s['ap_24h'] >= 2: ind.append(f"slow_ap({s['ap_24h']}/{len(s['approvals'])})")
    if s['changes_req'] >= 10: ind.append(f"chg_req({s['changes_req']})")
    if s['inc_severity'] >= 8: ind.append(f"inc({s['inc_count']}/{s['inc_severity']})")
    if s['rollbacks'] >= 2: ind.append(f"rollbk({s['rollbacks']})")
    if len(s['blocks_set']) >= 15: ind.append(f"blocks({len(s['blocks_set'])})")
    if s['qa_fails'] >= 4: ind.append(f"qa_fail({s['qa_fails']})")
    if s['msg_cnt'] > 300: ind.append(f"msgs({s['msg_cnt']})")
    if s['mtg_hours'] > 40: ind.append(f"mtgs({s['mtg_hours']:.0f}h)")
    print(f"{eid:>4} {sc:>6.1f} {e['seniority_level']:>10} {e['department']:>15} {', '.join(ind)}")

# Select answer: employees with score >= 8.0
answer = [eid for eid, sc in sorted_scores if sc >= 8.0]
print(f"\nAnswer (score >= 8.0): {answer}")
print(f"Count: {len(answer)}")

